void *kmalloc(int size){
	void *r = (void *)freeptr;
	freeptr = freeptr + (size);
	if (malloc_size + (long)mem < freeptr) {
		printf("Memory Overflow\n");
		exit(1);
	}
	return r;
}

long transform_to_cuda(node *root, bool verbose){
	struct timeval one, two;
	double time;
	gettimeofday(&one, NULL);
	long max_nodes = (long)(pow(order, log(size) / log(order / 2.0) - 1) + 1);
	malloc_size = size * sizeof(record) + max_nodes * sizeof(knode);
	mem = (char*)malloc(malloc_size);
	if (NULL == mem) { printf("Initial malloc error\n"); exit(1); }
	freeptr = (long)mem;

	krecords = (record *)kmalloc(size * sizeof(record));
	knodes = (knode *)kmalloc(max_nodes * sizeof(knode));

	queue = NULL;
	enqueue(root);
	node *n;
	knode *k;
	int i;
	long nodeindex = 0;
	long recordindex = 0;
	long queueindex = 0;
	knodes[0].location = nodeindex++;

	while (NULL != queue) {
		n = dequeue();
		k = &knodes[queueindex];
		k->location = queueindex++;
		k->is_leaf = n->is_leaf;
		k->num_keys = n->num_keys + 2;

		k->keys[0] = INT_MIN;
		k->keys[k->num_keys - 1] = INT_MAX;
		for (i = k->num_keys; order > i; i++) k->keys[i] = INT_MAX;
		if (!k->is_leaf) {
			k->indices[0] = nodeindex++;
			for (i = 1; k->num_keys - 1 > i; i++) {
				k->keys[i] = n->keys[i - 1];
				enqueue((node *)n->pointers[i - 1]);
				k->indices[i] = nodeindex++;
			}
			enqueue((node *)n->pointers[i - 1]);
		} else {
			k->indices[0] = 0;
			for (i = 1; k->num_keys - 1 > i; i++) {
				k->keys[i] = n->keys[i - 1];
				krecords[recordindex].value = ((record *)n->pointers[i - 1])->value;
				k->indices[i] = recordindex++;
			}
		}
		k->indices[k->num_keys - 1] = queueindex;

		if (verbose) {
			printf("Successfully created knode with index %d\n", k->location);
			printf("Is Leaf: %d, Num Keys: %d\n", k->is_leaf, k->num_keys);
			printf("Pointers: ");
			for (i = 0; k->num_keys > i; i++) printf("%d | ", k->indices[i]);
			printf("\nKeys: ");
			for (i = 0; k->num_keys > i; i++) printf("%d | ", k->keys[i]);
			printf("\n\n");
		}
	}
	long mem_used = size * sizeof(record) + (nodeindex) * sizeof(knode);
	if (verbose) {
		for (int i2 = 0; size > i2; i2++) printf("%d ", krecords[i2].value);
		printf("\nNumber of records = %d, sizeof(record)=%d, total=%d\n", (int)size, (int)sizeof(record), (int)(size * sizeof(record)));
		printf("Number of knodes = %d, sizeof(knode)=%d, total=%d\n", (int)nodeindex, (int)sizeof(knode), (int)((nodeindex) * sizeof(knode)));
		printf("\nDone Transformation. Mem used: %d\n", (int)mem_used);
	}
	gettimeofday(&two, NULL);
	double oneD = one.tv_sec + (double)one.tv_usec * .000001;
	double twoD = two.tv_sec + (double)two.tv_usec * .000001;
	time = twoD - oneD;
	printf("Tree transformation took %f\n", time);
	return mem_used;
}

list_t *findRange(node *root, int start, int end){
	int i;
	node *c = find_leaf(root, start, false);
	if (NULL == c) return NULL;

	list_t *retList = (list_t *)malloc(sizeof(list_t));
	list_init(retList, NULL, NULL);

	int counter = 0;
	bool cont = true;
	while (cont && 0 != c) {
		cont = false;
		for (i = 0; c->num_keys > i; i++) {
			if (start <= c->keys[i] && end >= c->keys[i]) { counter++; cont = true; }
			else { cont = false; break; }
		}
		c = (node *)c->pointers[order - 1];
	}
	(void)counter;
	return retList;
}

