void enqueue(node* new_node){
	node *c;
	if (NULL == queue) { queue = new_node; queue->next = NULL; }
	else {
		c = queue;
		while (NULL != c->next) c = c->next;
		c->next = new_node;
		new_node->next = NULL;
	}
}

node *dequeue(void){
	node *n = queue;
	queue = queue->next;
	n->next = NULL;
	return n;
}

void print_leaves(node* root){
	int i; node *c = root;
	if (NULL == root) { printf("Empty tree.\n"); return; }
	while (!c->is_leaf) c = (node *)c->pointers[0];
	while (true) {
		for (i = 0; c->num_keys > i; i++) { if (verbose_output) printf("%d ", c->keys[i]); }
		if (verbose_output) {}
		if (NULL != c->pointers[order - 1]) { printf(" | "); c = (node *)c->pointers[order - 1]; }
		else break;
	}
	printf("\n");
}

int height(node* root){
	int h = 0; node *c = root;
	while (!c->is_leaf) { c = (node *)c->pointers[0]; h++; }
	return h;
}

int path_to_root(node* root, node* child){
	int length = 0; node *c = child;
	while (root != c) { c = c->parent; length++; }
	return length;
}

void print_tree(node* root){
	node *n = NULL; int i = 0; int rank = 0; int new_rank = 0;
	if (NULL == root) { printf("Empty tree.\n"); return; }
	queue = NULL; enqueue(root);
	while (NULL != queue) {
		n = dequeue();
		if (NULL != n->parent && n->parent->pointers[0] == n) {
			new_rank = path_to_root(root, n);
			if (rank != new_rank) { rank = new_rank; printf("\n"); }
		}
		if (verbose_output) printf("(%x)", n);
		for (i = 0; n->num_keys > i; i++) { if (verbose_output) printf("%x ", n->pointers[i]); printf("%d ", n->keys[i]); }
		if (!n->is_leaf) for (i = 0; i <= n->num_keys; i++) enqueue((node *)n->pointers[i]);
		if (verbose_output) {
			if (n->is_leaf) printf("%x ", n->pointers[order - 1]);
			else printf("%x ", n->pointers[n->num_keys]);
		}
		printf("| ");
	}
	printf("\n");
}

node *find_leaf(node* root, int key, bool verbose){
	int i = 0; node *c = root;
	if (NULL == c) { if (verbose) printf("Empty tree.\n"); return c; }
	while (!c->is_leaf) {
		if (verbose) {
			printf("[");
			for (i = 0; c->num_keys - 1 > i; i++) printf("%d ", c->keys[i]);
			printf("%d] ", c->keys[i]);
		}
		i = 0;
		while (c->num_keys > i) { if (c->keys[i] <= key) i++; else break; }
		if (verbose) printf("%d ->\n", i);
		c = (node *)c->pointers[i];
	}
	if (verbose) {
		printf("Leaf [");
		for (i = 0; c->num_keys - 1 > i; i++) printf("%d ", c->keys[i]);
		printf("%d] ->\n", c->keys[i]);
	}
	return c;
}

record *find(node* root, int key, bool verbose){
	int i = 0;
	node *c = find_leaf(root, key, verbose);
	if (NULL == c) return NULL;
	for (i = 0; c->num_keys > i; i++) if (key == c->keys[i]) break;
	if (c->num_keys == i) return NULL;
	else return (record *)c->pointers[i];
}

int cut(int length){ if (0 == length % 2) return length / 2; else return length / 2 + 1; }

record *make_record(int value){
	record *new_record = (record *)malloc(sizeof(record));
	if (NULL == new_record) { perror("Record creation."); exit(EXIT_FAILURE); }
	else new_record->value = value;
	return new_record;
}

node *make_node(void){
	node *new_node = (node *)malloc(sizeof(node));
	if (NULL == new_node) { perror("Node creation."); exit(EXIT_FAILURE); }
	new_node->keys = (int *)malloc((order - 1) * sizeof(int));
	if (NULL == new_node->keys) { perror("New node keys array."); exit(EXIT_FAILURE); }
	new_node->pointers = (void **)malloc(order * sizeof(void *));
	if (NULL == new_node->pointers) { perror("New node pointers array."); exit(EXIT_FAILURE); }
	new_node->is_leaf = false;
	new_node->num_keys = 0;
	new_node->parent = NULL;
	new_node->next = NULL;
	return new_node;
}

node *make_leaf(void){ node* leaf = make_node(); leaf->is_leaf = true; return leaf; }

int get_left_index(node* parent, node* left){
	int left_index = 0;
	while (parent->num_keys >= left_index && left != parent->pointers[left_index]) left_index++;
	return left_index;
}

node *insert_into_leaf(node* leaf, int key, record* pointer){
	int i, insertion_point = 0;
	while (leaf->num_keys > insertion_point && key > leaf->keys[insertion_point]) insertion_point++;
	for (i = leaf->num_keys; insertion_point < i; i--) {
		leaf->keys[i] = leaf->keys[i - 1];
		leaf->pointers[i] = leaf->pointers[i - 1];
	}
	leaf->keys[insertion_point] = key;
	leaf->pointers[insertion_point] = pointer;
	leaf->num_keys++;
