__global__ void kernel_find_k(record *records,
							  knode *knodes,
							  long knodes_elem,
							  int order,
							  long maxheight,
							  int count,
							  long *currKnode,
							  long *offset,
							  int *keys,
							  record *ans)
{
	int bid = blockIdx.x * blockDim.x + threadIdx.x;
	if (bid >= count) return;

	int threadsPerBlock = (1024 > order) ? order : 1024;

	for (long i = 0; i < maxheight; i++) {
		long curr = currKnode[bid];
		long off = offset[bid];

		for (int thid = 0; thid < threadsPerBlock; thid++) {
			if (keys[bid] >= (knodes[curr].keys[thid]) &&
				(keys[bid] < knodes[curr].keys[thid + 1])) {
				if (knodes_elem > knodes[off].indices[thid]) {
					off = knodes[off].indices[thid];
				}
			}
		}

		offset[bid] = off;
		currKnode[bid] = off;
	}

	for (int thid = 0; thid < threadsPerBlock; thid++) {
		if (keys[bid] == knodes[currKnode[bid]].keys[thid]) {
			ans[bid].value = records[knodes[currKnode[bid]].indices[thid]].value;
		}
	}
}

__global__ void kernel_find_range(knode *knodes,
								  long knodes_elem,
								  int order,
								  long maxheight,
								  int count,
								  long *currKnode,
								  long *offset,
								  long *lastKnode,
								  long *offset_2,
								  int *start,
								  int *end,
								  int *recstart,
								  int *reclength)
{
	int bid = blockIdx.x * blockDim.x + threadIdx.x;
	if (bid >= count) return;

	int threadsPerBlock = (1024 > order) ? order : 1024;

	for (long i = 0; i < maxheight; i++) {
		long curr = currKnode[bid];
		long last = lastKnode[bid];
		long off = offset[bid];
		long off2 = offset_2[bid];

		for (int thid = 0; thid < threadsPerBlock; thid++) {
			if ((start[bid] >= knodes[curr].keys[thid]) &&
				(start[bid] < knodes[curr].keys[thid + 1])) {
				if (knodes_elem > knodes[curr].indices[thid]) {
					off = knodes[curr].indices[thid];
				}
			}
			if ((end[bid] >= knodes[last].keys[thid]) &&
				(end[bid] < knodes[last].keys[thid + 1])) {
				if (knodes_elem > knodes[last].indices[thid]) {
					off2 = knodes[last].indices[thid];
				}
			}
		}

		offset[bid] = off;
		offset_2[bid] = off2;
		currKnode[bid] = off;
		lastKnode[bid] = off2;
	}

	for (int thid = 0; thid < threadsPerBlock; thid++) {
		if (start[bid] == knodes[currKnode[bid]].keys[thid]) {
			recstart[bid] = knodes[currKnode[bid]].indices[thid];
		}
	}

	for (int thid = 0; thid < threadsPerBlock; thid++) {
		if (end[bid] == knodes[lastKnode[bid]].keys[thid]) {
			reclength[bid] = knodes[lastKnode[bid]].indices[thid] - recstart[bid] + 1;
		}
	}
}

extern "C"
void kernel_gpu_cuda_wrapper(record *records,
							 long records_mem,
							 knode *knodes,
							 long knodes_elem,
							 long knodes_mem,
							 int order,
							 long maxheight,
							 int count,
							 long *currKnode,
							 long *offset,
							 int *keys,
							 record *ans)
{
	(void)records_mem;

	record *d_records = NULL;
	knode *d_knodes = NULL;
	long *d_currKnode = NULL;
	long *d_offset = NULL;
	int *d_keys = NULL;
	record *d_ans = NULL;

	setdevice();

	cudaMalloc((void **)&d_records, sizeof(record) * ((size_t)records_mem / sizeof(record)));
	cudaMalloc((void **)&d_knodes, (size_t)knodes_mem);
	cudaMalloc((void **)&d_currKnode, sizeof(long) * (size_t)count);
	cudaMalloc((void **)&d_offset, sizeof(long) * (size_t)count);
	cudaMalloc((void **)&d_keys, sizeof(int) * (size_t)count);
	cudaMalloc((void **)&d_ans, sizeof(record) * (size_t)count);
	checkCUDAError("CUDA malloc");

	cudaMemcpy(d_records, records, sizeof(record) * ((size_t)records_mem / sizeof(record)), cudaMemcpyHostToDevice);
	cudaMemcpy(d_knodes, knodes, (size_t)knodes_mem, cudaMemcpyHostToDevice);
	cudaMemcpy(d_currKnode, currKnode, sizeof(long) * (size_t)count, cudaMemcpyHostToDevice);
	cudaMemcpy(d_offset, offset, sizeof(long) * (size_t)count, cudaMemcpyHostToDevice);
	cudaMemcpy(d_keys, keys, sizeof(int) * (size_t)count, cudaMemcpyHostToDevice);
	cudaMemcpy(d_ans, ans, sizeof(record) * (size_t)count, cudaMemcpyHostToDevice);
	checkCUDAError("CUDA memcpy H2D");

	int block_size = 256;
	int grid_size = (count + block_size - 1) / block_size;
	kernel_find_k<<<grid_size, block_size>>>(d_records, d_knodes, knodes_elem, order, maxheight, count, d_currKnode, d_offset, d_keys, d_ans);
	cudaDeviceSynchronize();
	checkCUDAError("kernel_find_k");

	cudaMemcpy(currKnode, d_currKnode, sizeof(long) * (size_t)count, cudaMemcpyDeviceToHost);
	cudaMemcpy(offset, d_offset, sizeof(long) * (size_t)count, cudaMemcpyDeviceToHost);
	cudaMemcpy(ans, d_ans, sizeof(record) * (size_t)count, cudaMemcpyDeviceToHost);
	checkCUDAError("CUDA memcpy D2H");

	cudaFree(d_records);
	cudaFree(d_knodes);
	cudaFree(d_currKnode);
	cudaFree(d_offset);
	cudaFree(d_keys);
	cudaFree(d_ans);
}

